package format

import (
	"strings"
	"testing"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

func TestCompactDiffFormatterNoChanges(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create an empty plan
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}

	schemas := &schemarepo.Schemas{}

	output := formatter.Format(plan, schemas)

	// Should contain summary
	if !strings.Contains(output, "Summary") {
		t.Errorf("Expected 'Summary' in output, got: %s", output)
	}
	if !strings.Contains(output, "No changes") {
		t.Errorf("Expected 'No changes' in output, got: %s", output)
	}
}

func TestCompactDiffFormatterWithChanges(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}

	// Add a create action
	plan.Changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
		Addr: addrs.Resource{
			Mode: addrs.ManagedResourceMode,
			Type: "aws_instance",
			Name: "web",
		}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
		ProviderAddr: addrs.AbsProviderConfig{
			Provider: addrs.NewDefaultProvider("aws"),
			Module:   addrs.RootModule,
		},
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	})

	// Add an update action
	plan.Changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
		Addr: addrs.Resource{
			Mode: addrs.ManagedResourceMode,
			Type: "aws_subnet",
			Name: "private",
		}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
		ProviderAddr: addrs.AbsProviderConfig{
			Provider: addrs.NewDefaultProvider("aws"),
			Module:   addrs.RootModule,
		},
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Update,
		},
	})

	// Add a delete action
	plan.Changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
		Addr: addrs.Resource{
			Mode: addrs.ManagedResourceMode,
			Type: "aws_security_group",
			Name: "old",
		}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
		ProviderAddr: addrs.AbsProviderConfig{
			Provider: addrs.NewDefaultProvider("aws"),
			Module:   addrs.RootModule,
		},
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Delete,
		},
	})

	schemas := &schemarepo.Schemas{}

	output := formatter.Format(plan, schemas)

	// Check for action groups
	if !strings.Contains(output, "create") {
		t.Errorf("Expected 'create' in output, got: %s", output)
	}
	if !strings.Contains(output, "update") {
		t.Errorf("Expected 'update' in output, got: %s", output)
	}
	if !strings.Contains(output, "delete") {
		t.Errorf("Expected 'delete' in output, got: %s", output)
	}

	// Check for resource addresses
	if !strings.Contains(output, "aws_instance.web") {
		t.Errorf("Expected 'aws_instance.web' in output, got: %s", output)
	}
	if !strings.Contains(output, "aws_subnet.private") {
		t.Errorf("Expected 'aws_subnet.private' in output, got: %s", output)
	}
	if !strings.Contains(output, "aws_security_group.old") {
		t.Errorf("Expected 'aws_security_group.old' in output, got: %s", output)
	}

	// Check for summary
	if !strings.Contains(output, "1 create") {
		t.Errorf("Expected '1 create' in output, got: %s", output)
	}
	if !strings.Contains(output, "1 update") {
		t.Errorf("Expected '1 update' in output, got: %s", output)
	}
	if !strings.Contains(output, "1 delete") {
		t.Errorf("Expected '1 delete' in output, got: %s", output)
	}
}

func TestCompactDiffFormatterNilPlan(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	output := formatter.Format(nil, nil)

	if output != "" {
		t.Errorf("Expected empty string for nil plan, got: %s", output)
	}
}

func TestCompactDiffFormatterWithReplace(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}

	// Add a replace action
	plan.Changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
		Addr: addrs.Resource{
			Mode: addrs.ManagedResourceMode,
			Type: "aws_instance",
			Name: "primary",
		}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
		ProviderAddr: addrs.AbsProviderConfig{
			Provider: addrs.NewDefaultProvider("aws"),
			Module:   addrs.RootModule,
		},
		ChangeSrc: plans.ChangeSrc{
			Action: plans.DeleteThenCreate,
		},
	})

	schemas := &schemarepo.Schemas{}

	output := formatter.Format(plan, schemas)

	// Check for replace in output
	if !strings.Contains(output, "replace") {
		t.Errorf("Expected 'replace' in output, got: %s", output)
	}
	if !strings.Contains(output, "aws_instance.primary") {
		t.Errorf("Expected 'aws_instance.primary' in output, got: %s", output)
	}
	if !strings.Contains(output, "1 replace") {
		t.Errorf("Expected '1 replace' in output, got: %s", output)
	}
}

